(1,'Tes','erlan@trakerja.web.id','Ingin berlangganan baru atau perpanjang?','tes','unread','2a02:26f7:dfcc:46c6:0:f000:0:c','2026-05-16 11:38:27','2026-05-16 11:38:27');
INSERT INTO `cover_letters` VALUES
(1,119,'PT Tiga Inspirasi Bersama','Performance Marketing Specialist','• Setup, manage, dan optimasi campaign Meta Ads & Google Ads untuk lead generation • Generate leads untuk sales funnel • Jalankan A/B testing','id','professional','Semarang, 29 Oktober 2023\n\nYth. Tim Rekrutmen PT Tiga Inspirasi Bersama  \nDi Tempat  \n\nDengan hormat,  \n\nSaya Fariq Yusran Rizkia, tertarik untuk melamar posisi Performance Marketing Specialist di PT Tiga Inspirasi Bersama yang saya temukan melalui informasi lowongan kerja. Dengan pengalaman sebagai Business & Operations Intern di PT Penjamin Kredit Indonesia Syariah, saya memiliki pemahaman yang baik terkait pengelolaan dan optimasi proses yang relevan dengan kebutuhan perusahaan.\n\nSelama magang, saya berhasil memproses dan mencatat lebih dari 10 transaksi biaya layanan kafalah, yang menunjukkan kemampuan saya dalam mengelola data dan menjaga akurasi dokumentasi. Selain itu, saya terlibat dalam pembuatan materi untuk komite internal dan dokumen finansial yang mendukung pengambilan keputusan operasional. Keterampilan ini saya yakini akan berkontribusi dalam pengelolaan campaign Meta Ads dan Google Ads untuk lead generation di PT Tiga Inspirasi Bersama.\n\nSaya sangat antusias untuk bergabung dan berkontribusi dalam tim Anda. Saya siap untuk berdiskusi lebih lanjut mengenai bagaimana saya dapat membantu mencapai target perusahaan. Terima kasih atas perhatian Anda.  \n\nHormat saya,  \nFariq Yusran Rizkia  \nfariqyr@gmail.com','2026-05-16 19:35:28','2026-05-16 19:35:28'),
(2,119,'Unit Wakaf IPB University','Staff Program','- Menyiapkan Dokumen Keperluan Program\r\n- Membuat Laporan Program\r\n- Copywriter\r\n- Admin Sosmed','id','professional','Kuningan, 4 Oktober 2023\n\nYth. Tim Rekrutmen Unit Wakaf IPB University  \nDi Tempat\n\nDengan hormat,\n\nDengan ini saya mengajukan lamaran untuk posisi Staff Program di Unit Wakaf IPB University. Saya mengetahui lowongan ini melalui situs resmi IPB University dan sangat tertarik untuk berkontribusi dalam program-program sosial yang berdampak. Sebagai lulusan Ekonomi Islam dari Universitas Diponegoro, saya memiliki pemahaman yang mendalam tentang filantropi, terutama dalam pengelolaan zakat, yang saya peroleh melalui pengalaman saya sebagai Finance Assistant Intern di Badan Amil Zakat Nasional.\n\nPengalaman saya sebagai Communication Assistant Intern di Asosiasi Fintech Syariah Indonesia juga memperkuat kemampuan saya dalam menyusun materi komunikasi dan laporan yang sistematis. Saya percaya keterampilan administratif, pengolahan data, dan komunikasi yang saya miliki akan mendukung pelaksanaan program di Unit Wakaf IPB University. Saya sangat antusias untuk bekerja dalam lingkungan kolaboratif dan berkontribusi pada inisiatif yang berkelanjutan.\n\nSaya berharap dapat mendiskusikan lebih lanjut tentang bagaimana saya dapat memberikan kontribusi positif di Unit Wakaf IPB University. Terima kasih atas perhatian Bapak/Ibu. \n\nHormat saya,  \nFariq Yusran Rizkia  \n(62) 851-5654-7112  \nfariqyr@gmail.com','2026-05-16 20:07:28','2026-05-16 20:07:28'),
(3,4,'PT Teknalogi Transformasi Digital','Associate AI Engineer','# Associate AI Engineer\r\n\r\ndi PT Teknalogi Transformasi Digital\r\n\r\n## Job Description\r\n\r\nKami mencari Associate AI Engineer yang memiliki semangat belajar tinggi dan tertarik mengembangkan solusi berbasis Artificial Intelligence untuk mendukung transformasi digital perusahaan. Posisi ini akan bekerja bersama tim engineering dan product dalam pengembangan, implementasi, serta optimalisasi model AI/ML pada berbagai kebutuhan bisnis.\r\n\r\n## Responsibilities\r\n\r\n* Membantu pengembangan dan implementasi solusi Artificial Intelligence dan Machine Learning.\r\n* Melakukan data preprocessing, data analysis, dan feature engineering.\r\n* Membantu proses training, testing, dan evaluasi model AI/ML.\r\n* Berkolaborasi dengan tim developer dan product dalam integrasi model AI ke aplikasi atau sistem perusahaan.\r\n* Membuat dokumentasi teknis terkait pengembangan model dan deployment.\r\n* Melakukan riset sederhana terkait teknologi AI terbaru untuk mendukung inovasi produk.\r\n\r\n## Requirements\r\n\r\n* Minimal S1 Informatika, Ilmu Komputer, Sistem Informasi, Data Science, atau jurusan terkait.\r\n* Memahami dasar Artificial Intelligence, Machine Learning, atau Deep Learning.\r\n* Menguasai Python untuk pengembangan dan pengolahan data.\r\n* Familiar dengan library/framework seperti Scikit-learn, TensorFlow, PyTorch, atau Hugging Face.\r\n* Memahami dasar SQL dan pengolahan database.\r\n* Familiar dengan REST API dan Git/GitHub.\r\n* Memiliki kemampuan analytical thinking dan problem solving yang baik.\r\n* Mampu bekerja secara individu maupun tim.\r\n* Bersedia belajar dan beradaptasi dengan teknologi baru.\r\n\r\n## Preferred Qualifications\r\n\r\n* Memiliki portfolio/project AI, NLP, Computer Vision, atau Generative AI.\r\n* Familiar dengan deployment model AI, FastAPI, Docker, atau cloud platform (GCP/AWS/Azure).\r\n* Memiliki pengalaman internship, bootcamp, atau kompetisi terkait AI/Data Science menjadi nilai tambah.\r\n\r\n## Why Join Us?\r\n\r\n* Kesempatan berkembang di industri AI dan transformasi digital.\r\n* Lingkungan kerja kolaboratif dan inovatif.\r\n* Exposure terhadap project AI nyata untuk kebutuhan bisnis.\r\n* Kesempatan belajar dan berkembang bersama tim teknologi berpengalaman.','id','professional','Jakarta, 10 Oktober 2023\n\nYth. Tim Rekrutmen PT Teknalogi Transformasi Digital\nDi Tempat\n\nDengan hormat,\n\nSaya, Erlan, menulis untuk mengajukan lamaran pada posisi Associate AI Engineer di PT Teknalogi Transformasi Digital, yang saya ketahui melalui situs karir. Dengan ketertarikan yang mendalam terhadap teknologi Artificial Intelligence dan semangat untuk terus belajar, saya yakin dapat memberikan kontribusi yang berarti bagi tim Anda.\n\nMeskipun saya belum memiliki pengalaman kerja formal, saya telah mengembangkan pengetahuan yang kuat dalam bidang AI dan Machine Learning melalui berbagai sumber belajar dan proyek pribadi. Saya memahami dasar-dasar AI dan ML, serta memiliki kemampuan dalam pemrograman menggunakan Python. Selain itu, saya familiar dengan beberapa library seperti Scikit-learn dan TensorFlow, yang saya gunakan dalam eksperimen pengolahan data dan pengembangan model sederhana. Saya percaya kemampuan ini akan sangat mendukung tugas saya dalam membantu pengembangan dan implementasi solusi AI di PT Teknalogi Transformasi Digital.\n\nSaya sangat antusias untuk bergabung dengan tim inovatif di PT Teknalogi Transformasi Digital dan berkontribusi dalam proyek-proyek nyata yang akan mendukung transformasi digital perusahaan. Saya siap untuk berkolaborasi dan belajar dari tim yang berpengalaman, serta berkomitmen untuk membawa solusi yang efektif dan efisien. Saya berharap dapat mendiskusikan lebih lanjut tentang kontribusi yang dapat saya berikan dalam wawancara mendatang.\n\nTerima kasih atas perhatian dan kesempatan yang diberikan. Saya menanti kabar baik dari Anda.\n\nHormat saya,\n\nErlan  \nerlanig221@gmail.com','2026-05-21 08:20:52','2026-05-21 08:20:52'),
(4,119,'PT. Trinusa Resources','Admin HR','🔎 Kualifikasi:\r\n– Pria/Wanita\r\n– Pendidikan minimal D3/S1 dari semua jurusan\r\n– Mampu mengoperasikan Microsoft Office\r\n– Teliti, disiplin, dan memiliki kemampuan komunikasi yang baik\r\n– Bersedia melakukan perjalanan dinas ke luar kota\r\n– Memiliki pengalaman sebagai administrasi HR\r\n– Mampu bekerja secara individu maupun dalam tim\r\n– Bersedia ditempatkan di Head Office Jakarta\r\n\r\n🧩 Job Responsibilities:\r\n– Mengelola administrasi HR perusahaan\r\n– Membantu pengelolaan data & dokumen karyawan\r\n– Mendukung kebutuhan operasional administrasi SDM\r\n– Berkoordinasi dengan tim terkait untuk kebutuhan administrasi HR','id','professional','Kuningan, 7 Oktober 2023\n\nYth. Tim Rekrutmen PT. Trinusa Resources  \nDi Tempat  \n\nDengan hormat,\n\nSaya, Fariq Yusran Rizkia, bermaksud melamar posisi Admin HR di PT. Trinusa Resources yang saya ketahui melalui platform pencarian kerja. Dengan latar belakang pendidikan di Ekonomi Islam dan pengalaman dalam pengelolaan administrasi, saya yakin dapat memberikan kontribusi yang signifikan bagi tim di perusahaan ini.\n\nSelama pengalaman saya sebagai anggota kerja di Badan Eksekutif Mahasiswa Fakultas Ekonomi dan Bisnis, saya terlibat dalam proses rekrutmen dan perencanaan program kerja yang mendukung pengembangan sumber daya manusia. Saya berhasil mengkoordinasikan kegiatan yang melibatkan lebih dari 1000 mahasiswa, memastikan setiap tahap berjalan efektif dan sesuai dengan kebutuhan organisasi. Keahlian saya dalam Microsoft Excel juga mendukung kemampuan saya dalam mengolah dan menganalisis data, yang sangat penting dalam pengelolaan dokumen karyawan dan pelaporan yang akurat.\n\nSelain itu, pengalaman magang saya di berbagai organisasi, termasuk sebagai Business & Operations Intern di PT Penjamin Kredit Indonesia, telah membekali saya dengan keterampilan administrasi yang kuat dan pemahaman tentang kepatuhan operasional. Saya terbiasa mengelola dokumen dan berkoordinasi dengan berbagai pihak, sehingga saya yakin dapat mendukung kebutuhan operasional administrasi SDM di PT. Trinusa Resources dengan baik.\n\nSaya sangat antusias untuk bergabung dengan PT. Trinusa Resources dan berkontribusi pada inisiatif yang berdampak serta berkelanjutan. Saya berharap dapat mendiskusikan lebih lanjut bagaimana saya dapat berkontribusi dalam tim. Terima kasih atas perhatian dan kesempatan yang diberikan.\n\nHormat saya,  \nFariq Yusran Rizkia  \n(62) 851-5654-7112  \nfariqyr@gmail.com','2026-05-25 10:16:10','2026-05-25 10:16:10'),
(5,119,'PT Global Digital Niaga Tbk (BliBli)','ESG Program Junior Officer','Job Description:\r\nInitiate and support ESG programs, including planning, execution, and evaluation.\r\nBuild and manage partnerships with external stakeholders (sponsors, communities, organizations).\r\nCoordinate ESG program planning, timelines, and execution to ensure smooth delivery.\r\nNegotiate with partners and vendors to ensure mutually beneficial collaboration.\r\nManage project timelines, identify risks, and resolve issues to keep programs on track.\r\nEnsure ESG initiatives are not only impactful but also financially sustainable and efficient.\r\nCollaborate cross-functionally with internal teams to align ESG initiatives with business goals.\r\nMonitor program performance and provide reports, insights, and recommendations.\r\n\r\nRecommendation:\r\nBachelor’s degree (S1) in any relevant field.\r\nFresh graduates or candidates with project management, partnership, or sponsorship experience are welcome.\r\nStrong interest in sustainability, ESG initiatives, and social impact programs.\r\nGood project management and organizational skills.\r\nStrong communication and negotiation skills when dealing with external partners.\r\nProblem-solving mindset, especially in managing timelines and execution challenges.\r\nProactive, detail-oriented, and able to manage multiple initiatives simultaneously.','en','professional','Kuningan, October 10, 2023\n\nDear Hiring Committee,\n\nI am writing to express my interest in the ESG Program Junior Officer position at PT Global Digital Niaga Tbk (BliBli), which I discovered through your careers page. As a fresh graduate in Islamic Economics with a keen focus on human capital development and social impact, I am excited about the opportunity to contribute to your esteemed organization’s sustainability initiatives.\n\nDuring my internship at PT Penjamin Kredit Indonesia, I honed my data processing and analytical skills by managing over 250 consumer data records, which directly supported operational decision-making. Furthermore, my role as a Communication Assistant at Asosiasi Fintech Syariah Indonesia allowed me to coordinate various stakeholder communications, which is vital for building and managing partnerships as outlined in your job description. I am adept at project planning and execution, having collaborated cross-functionally to ensure timely delivery of projects while monitoring performance metrics, aligning perfectly with the requirements of the ESG Program Junior Officer role.\n\nI am enthusiastic about the potential to join PT Global Digital Niaga Tbk and contribute to impactful ESG initiatives. I am eager to discuss how my background and skills can align with your team’s goals. Thank you for considering my application. I look forward to the opportunity for an interview.\n\nSincerely,  \nFariq Yusran Rizkia  \n(62) 851-5654-7112  \nfariqyr@gmail.com','2026-06-07 19:28:03','2026-06-07 19:28:03');
