INSERT INTO `support_tickets` VALUES
(7,254,NULL,NULL,'technical_issue','AI Analyze Tidak Bisa Upload CV – Error 400','Saya mengalami kendala pada fitur AI Analyze di website trakerja.web.id. Saat melakukan upload CV, file sebenarnya sudah berhasil terupload dan tampil berhasil dipilih, namun ketika melanjutkan proses muncul error 400 dengan pesan bahwa saya harus upload CV terlebih dahulu.\r\n\r\nPadahal file CV sudah saya upload sebelumnya. Saya sudah mencoba beberapa kali tetapi hasilnya tetap sama.\r\n\r\nMohon dicek dan dibantu perbaikannya. Terima kasih.','completed','Halo Kak Luthfi,\r\n\r\nTerima kasih atas kesabarannya menunggu.\r\n\r\nKami ingin mengabarkan bahwa tim developer kami telah selesai melakukan pengecekan dan perbaikan terkait kendala \"Error 400\" pada fitur AI Analyze.\r\n\r\nMasalah tersebut terjadi karena adanya ketidaksesuaian pada sistem pengiriman file dokumen, dan saat ini sistem upload CV sudah kembali berjalan dengan normal.\r\n\r\nSilakan mencoba untuk melakukan analisa kembali menggunakan CV Anda. Jika masih menemukan kendala atau ada pertanyaan lainnya, jangan ragu untuk membalas email/tiket ini ya.\r\n\r\nSekali lagi, mohon maaf atas ketidaknyamanan yang sempat terjadi dan terima kasih telah menggunakan TraKerja!\r\n\r\nSalam Hangat, Tim Support TraKerja','2026-06-09 14:03:21','2026-05-28 19:26:23','2026-06-09 14:03:21');
